+import { $internal } from '../common';
+import type { Trait, TraitRecord, TraitValue } from '../trait/types';
+
+export const $aspect = Symbol('koota.aspect');
+
+export type AspectTraits = readonly Trait[];
+
+export type Aspect<TTraits extends AspectTraits = AspectTraits> = {
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: Record<string, unknown>;
+    readonly [$aspect]: true;
+} & ((params?: AspectValue<TTraits>) => [Aspect<TTraits>, AspectValue<TTraits>]);
+
+export type AspectValue<TTraits extends AspectTraits = AspectTraits> =
+    TTraits[number] extends infer T extends Trait ? Partial<TraitRecord<T>> : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$aspect];
+}
+
+/** Creates a composite view over two or more non-relation traits. */
+export function createAspect<T extends readonly (Trait | Aspect)[]>(...inputs: T): Aspect {
+    if (inputs.length < 2) throw new Error('Koota: createAspect requires at least two traits.');
+
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        const constituents = isAspect(input) ? input.traits : [input];
+        for (const trait of constituents) {
+            if (trait[$internal].relation) {
+                throw new Error('Koota: relation traits cannot be constituents of an aspect.');
+            }
+            if (!traits.includes(trait)) traits.push(trait);
+        }
+    }
+
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        const traitSchema = trait.schema;
+        const fields =
+            typeof traitSchema === 'function' ? (traitSchema() as Record<string, unknown>) : traitSchema;
+        for (const field of Object.keys(fields)) {
+            if (field in schema) {
+                throw new Error(`Koota: aspect constituents overlap on field "${field}".`);
+            }
+            schema[field] = fields[field];
+        }
+    }
+
+    const id = aspectId++;
+    const aspect = Object.assign((params: AspectValue) => [aspect, params] as const, {
+        [$aspect]: true as const,
+        id,
+        traits: Object.freeze(traits.slice()),
+        schema: Object.freeze(schema),
+    }) as Aspect;
+    return aspect;
+}
+
+export function aspectValues<T extends Trait>(aspect: Aspect, value: Record<string, unknown>, trait: T) {
+    const result: Record<string, unknown> = {};
+    const schema = trait.schema;
+    const fields = typeof schema === 'function' ? schema() : schema;
+    for (const field of Object.keys(fields)) {
+        if (field in value) result[field] = value[field];
+    }
+    return result as TraitValue<T['schema']>;
+}
