+import { $internal } from '../common';
+import { Aspect, aspectValues, isAspect } from '../aspect/aspect';
+import type { Entity } from '../entity/types';
+import { getEntityId } from '../entity/utils/pack-entity';
+import { isRelationPair } from '../relation/utils/is-relation';
+import { getStore } from '../trait/trait';
+import type { Trait } from '../trait/types';
+import { shallowEqual } from '../utils/shallow-equal';
+import type { World } from '../world';
+import { isModifier } from './modifier';
+import { setChanged } from './modifiers/changed';
+import type { InstancesFromParameters, QueryInstance, QueryParameter, QueryResult, QueryResultOptions, StoresFromParameters } from './types';
+
+type Entry = { traits: Trait[]; aspect?: Aspect };
+
+export function createQueryResult<T extends QueryParameter[]>(world: World, entities: Entity[], query: QueryInstance, params: QueryParameter[]): QueryResult<T> {
+    const entries = getEntries(params);
+    const results = Object.assign(entities, {
+        readEach(callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void) {
+            for (let i = 0; i < entities.length; i++) callback(readState(world, entities[i], entries), entities[i], i);
+            return results;
+        },
+        updateEach(callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void, options: QueryResultOptions = { changeDetection: 'auto' }) {
+            const changes: [Entity, Trait][] = [];
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = readState(world, entity, entries);
+                const before = state.map((value) => ({ ...value }));
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+                for (let j = 0; j < entries.length; j++) {
+                    const entry = entries[j];
+                    for (const trait of entry.traits) {
+                        if (trait[$internal].type === 'tag') continue;
+                        const value = entry.aspect ? aspectValues(entry.aspect, state[j], trait) : state[j];
+                        const oldValue = entry.aspect ? aspectValues(entry.aspect, before[j], trait) : before[j];
+                        const store = getStore(world, trait);
+                        const changed = trait[$internal].fastSetWithChangeDetection(getEntityId(entity), store, value) ||
+                            (trait[$internal].type === 'aos' && !shallowEqual(value, oldValue));
+                        const tracked = world[$internal].trackedTraits.has(trait) || (query.hasChangedModifiers && query.changedTraits.has(trait));
+                        if (options.changeDetection !== 'never' && changed && (options.changeDetection === 'always' || tracked)) changes.push([entity, trait]);
+                    }
+                }
+            }
+            for (const [entity, trait] of changes) setChanged(world, entity, trait);
+            return results;
+        },
+        useStores(callback: (stores: StoresFromParameters<T>, entities: readonly Entity[]) => void) {
+            callback(entries.flatMap((entry) => entry.traits.filter((trait) => trait[$internal].type !== 'tag').map((trait) => getStore(world, trait))) as StoresFromParameters<T>, entities);
+            return results;
+        },
+        select<U extends QueryParameter[]>(...selected: U): QueryResult<U> {
+            return createQueryResult<U>(world, entities, query, selected);
+        },
+        sort(callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)): QueryResult<T> {
+            Array.prototype.sort.call(entities, callback);
+            return results;
+        },
+    });
+    return results as QueryResult<T>;
+}
+
+function getEntries(params: QueryParameter[]): Entry[] {
+    const entries: Entry[] = [];
+    for (const param of params) {
+        if (isRelationPair(param)) continue;
+        if (isModifier(param)) {
+            if (param.type === 'not') continue;
+            if (param.aspect) entries.push({ traits: [...param.aspect.traits], aspect: param.aspect });
+            else for (const trait of param.traits) if (trait[$internal].type !== 'tag') entries.push({ traits: [trait] });
+        } else if (isAspect(param)) {
+            entries.push({ traits: [...param.traits], aspect: param });
+        } else if (param[$internal].type !== 'tag') entries.push({ traits: [param] });
+    }
+    return entries;
+}
+
+function readState(world: World, entity: Entity, entries: Entry[]): any[] {
+    const eid = getEntityId(entity);
+    return entries.map((entry) => {
+        if (entry.aspect) {
+            const value: Record<string, unknown> = {};
+            for (const trait of entry.traits) {
+                if (trait[$internal].type !== 'tag') Object.assign(value, trait[$internal].get(eid, getStore(world, trait)));
+            }
+            return value;
+        }
+        const trait = entry.traits[0];
+        return trait[$internal].get(eid, getStore(world, trait));
+    });
+}
+
+export function getQueryStores<T extends QueryParameter[]>(params: T, traits: Trait[], stores: any[], world: World) {
+    for (const entry of getEntries(params)) for (const trait of entry.traits) if (trait[$internal].type !== 'tag') { traits.push(trait); stores.push(getStore(world, trait)); }
+}
+
+export function createEmptyQueryResult(): QueryResult<QueryParameter[]> {
+    return createQueryResult({} as World, [], {} as QueryInstance, []);
+}
+
+export function createRelationOnlyQueryResult<T extends QueryParameter[]>(entities: Entity[]): QueryResult<T> {
+    return createQueryResult({} as World, entities, {} as QueryInstance, []);
+}
